import { MakeLogicType, actions, connect, kea, listeners, path, reducers, selectors } from 'kea'

import { eventUsageLogic } from 'lib/utils/eventUsageLogic'

import { RevenueAnalyticsMRRQueryResultItem } from '~/queries/schema/schema-general'
import { GraphDataset } from '~/types'

const includeKey =
    (key: `revenue-analytics-${keyof RevenueAnalyticsMRRQueryResultItem}`) => (dataset: GraphDataset) => ({
        ...dataset,
        status: key,
    })

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface mrrBreakdownModalLogicValues {
    churnDatasets: GraphDataset[]
    contractionDatasets: GraphDataset[]
    data: RevenueAnalyticsMRRQueryResultItem[] | null
    expansionDatasets: GraphDataset[]
    isModalOpen: boolean
    newDatasets: GraphDataset[]
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface mrrBreakdownModalLogicActions {
    reportRevenueAnalyticsMRRBreakdownModalOpened: () => {} // eventUsageLogic
    closeModal: () => {
        value: true
    }
    openModal: (data: RevenueAnalyticsMRRQueryResultItem[]) => RevenueAnalyticsMRRQueryResultItem[]
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface mrrBreakdownModalLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        isModalOpen: (data: RevenueAnalyticsMRRQueryResultItem[] | null) => boolean
        newDatasets: (data: RevenueAnalyticsMRRQueryResultItem[] | null) => GraphDataset[]
        expansionDatasets: (data: RevenueAnalyticsMRRQueryResultItem[] | null) => GraphDataset[]
        contractionDatasets: (data: RevenueAnalyticsMRRQueryResultItem[] | null) => GraphDataset[]
        churnDatasets: (data: RevenueAnalyticsMRRQueryResultItem[] | null) => GraphDataset[]
    }
}

export type mrrBreakdownModalLogicType = MakeLogicType<
    mrrBreakdownModalLogicValues,
    mrrBreakdownModalLogicActions,
    Record<string, any>,
    mrrBreakdownModalLogicMeta
>

export const mrrBreakdownModalLogic = kea<mrrBreakdownModalLogicType>([
    path(['products', 'revenueAnalytics', 'mrrBreakdownModalLogic']),
    connect(() => ({
        actions: [eventUsageLogic, ['reportRevenueAnalyticsMRRBreakdownModalOpened']],
    })),

    actions({
        openModal: (data: RevenueAnalyticsMRRQueryResultItem[]) => data,
        closeModal: true,
    }),

    reducers({
        data: [
            null as RevenueAnalyticsMRRQueryResultItem[] | null,
            {
                openModal: (_, data) => data,
                closeModal: () => null,
            },
        ],
    }),

    selectors({
        isModalOpen: [(s) => [s.data], (data: RevenueAnalyticsMRRQueryResultItem[] | null): boolean => !!data],
        newDatasets: [
            (s) => [s.data],
            (data: RevenueAnalyticsMRRQueryResultItem[] | null): GraphDataset[] =>
                (data?.map((item) => item.new as GraphDataset) ?? []).map(includeKey('revenue-analytics-new')),
        ],
        expansionDatasets: [
            (s) => [s.data],
            (data: RevenueAnalyticsMRRQueryResultItem[] | null): GraphDataset[] =>
                (data?.map((item) => item.expansion as GraphDataset) ?? []).map(
                    includeKey('revenue-analytics-expansion')
                ),
        ],
        contractionDatasets: [
            (s) => [s.data],
            (data: RevenueAnalyticsMRRQueryResultItem[] | null): GraphDataset[] =>
                (data?.map((item) => item.contraction as GraphDataset) ?? []).map(
                    includeKey('revenue-analytics-contraction')
                ),
        ],
        churnDatasets: [
            (s) => [s.data],
            (data: RevenueAnalyticsMRRQueryResultItem[] | null): GraphDataset[] =>
                (data?.map((item) => item.churn as GraphDataset) ?? []).map(includeKey('revenue-analytics-churn')),
        ],
    }),

    listeners(({ actions }) => ({
        openModal: () => {
            actions.reportRevenueAnalyticsMRRBreakdownModalOpened()
        },
    })),
])
